it('Advance nonce - should not advance by 256', async function () {
    const { seriesEpochManager } = await loadFixture(deploySeriesEpochManager);
    await expect(seriesEpochManager.advanceEpoch(0, 256)).to.be.revertedWithCustomError(seriesEpochManager, 'AdvanceEpochFailed');
});

it('can be initialized with no pause window or buffer period duration', async () => {
  const pauseWindowDuration = 0;
  const bufferPeriodDuration = 0;

  await deployTemporarilyPausable({ pauseWindowDuration, bufferPeriodDuration });

  await assertPauseState(false, await currentTimestamp(), bufferPeriodDuration);
});

it('nonReentrant function can be called', async function () {
  expect(await this.mock.counter()).to.equal(0n);
  await this.mock.callback();
  expect(await this.mock.counter()).to.equal(1n);
});

it('does not allow local recursion', async function () {
  await expect(this.mock.countLocalRecursive(10n)).to.be.revertedWithCustomError(
    this.mock,
    'ReentrancyGuardReentrantCall',
  );
});

const deployTemporarilyPausable = async ({ pauseWindowDuration = 0, bufferPeriodDuration = 0 }) => {
  instance = await deploy('TemporarilyPausableMock', { args: [pauseWindowDuration, bufferPeriodDuration] });
};

export const receiptTimestamp = async (receipt: ContractReceipt | Promise<ContractReceipt>): Promise<number> => {
  const blockHash = (await receipt).blockHash;
  const block = await ethers.provider.getBlock(blockHash);
  return block.timestamp;
};

async function signOrder (order, chainId, target, wallet) {
    const orderData = buildOrderData(chainId, target, order);
    return await wallet.signTypedData(orderData.domain, orderData.types, orderData.value);
}

